def replay(self, start: Optional[datetime] = None, end: Optional[datetime] = None, event_type: Optional[str] = None) -> List[Event]:
    """Replay events within a time range, optionally filtered by type."""
    result = []
    for event in self._events:
        if start and event.timestamp < start:
            continue
        if end and event.timestamp > end:
            continue
        if event_type and event.type != event_type:
            continue
        result.append(event)
    return result
